namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber);
    Task<List<Shipment>> GetShipmentsForCustomerAsync(string email);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task UpdateStatusAsync(int id, ShipmentStatus status);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<List<Shipment>> GetShipmentsForCustomerAsync(string email)
    {
        return await http.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(email)}") ?? [];
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }

    public async Task UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = status });
        response.EnsureSuccessStatusCode();
    }
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.OrderByDescending(s => s.CreatedAt).ToListAsync();
    }

    public async Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        return await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<List<Shipment>> GetShipmentsForCustomerAsync(string email)
    {
        return await db.Shipments
            .Where(s => s.CustomerEmail == email)
            .OrderByDescending(s => s.CreatedAt)
            .ToListAsync();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        shipment.TrackingNumber = GenerateTrackingNumber();
        shipment.CreatedAt = DateTime.UtcNow;
        shipment.Status = ShipmentStatus.Pending;
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return shipment;
    }

    public async Task UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException($"Shipment {id} not found.");
        shipment.Status = status;
        await db.SaveChangesAsync();
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

