                            <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                            <td>@(s.CustomerEmail ?? "—")</td>
                            <td>
                                <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                        value="@s.Status"
                                        @onchange="e => UpdateStatus(s, e)">
                                    @foreach (var st in Enum.GetValues<ShipmentStatus>())
                                    {
                                        <option value="@st" selected="@(st == s.Status)">@st</option>
                                    }
                                </select>
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
        <p class="text-muted">Showing @filtered.Count of @shipments.Count shipments</p>
