@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private List<Shipment>? shipments;
    private string searchTerm = string.Empty;
    private string statusFilter = string.Empty;
    private bool showCreate;
    private bool isSaving;
    private Shipment newShipment = new();

    private List<Shipment> FilteredShipments
    {
        get
        {
            if (shipments is null) return [];
            var q = shipments.AsEnumerable();
            if (!string.IsNullOrWhiteSpace(searchTerm))
            {
                var term = searchTerm.Trim();
                q = q.Where(s =>
                    s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                    s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                    s.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
            }
            if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var st))
            {
                q = q.Where(s => s.Status == st);
            }
            return q.ToList();
        }
    }

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        newShipment = new Shipment { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
        showCreate = true;
    }

    private async Task CreateShipment()
    {
        isSaving = true;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        showCreate = false;
        isSaving = false;
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/my-shipments"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@attribute [Authorize]

<PageTitle>My Shipments</PageTitle>

<div class="container py-4">
    <h2>📦 My Shipments</h2>

    @if (shipments is null)
    {
        <p class="text-muted">Loading your shipments…</p>
    }
    else if (shipments.Count == 0)
    {
        <div class="alert alert-info">
            You have no shipments associated with your account yet.
        </div>
    }
    else
    {
        <div class="row g-3">
            @foreach (var s in shipments)
