                            <span class="badge @GetBadge(s.Status)">@s.Status</span>
                        </div>
                        <div class="card-body">
                            <h6 class="card-title">@s.Description</h6>
                            <p class="card-text mb-1">
                                <small class="text-muted">From:</small> @s.Origin
                            </p>
                            <p class="card-text mb-1">
                                <small class="text-muted">To:</small> @s.Destination
                            </p>
                            @if (s.EstimatedDelivery.HasValue)
                            {
                                <p class="card-text mb-0">
                                    <small class="text-muted">ETA:</small>
                                    <strong>@s.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</strong>
                                    @if (s.Status != ShipmentStatus.Delivered)
                                    {
                                        var daysLeft = (s.EstimatedDelivery.Value - DateTime.UtcNow).Days;
                                        <span class="text-muted ms-1">
                                            (@(daysLeft > 0 ? $"{daysLeft} day(s) away" : "arriving soon"))
                                        </span>
                                    }
                                </p>
                            }
                        </div>
                        <div class="card-footer text-muted">
                            <small>Shipped @s.CreatedAt.ToString("MMM dd, yyyy")</small>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;
    [CascadingParameter] private Task<AuthenticationState> AuthStateTask { get; set; } = default!;

    private List<Shipment>? shipments;

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthStateTask;
        var email = authState.User.Identity?.Name;
        if (!string.IsNullOrEmpty(email))
        {
            shipments = await ShipmentService.GetShipmentsForCustomerAsync(email);
        }
        else
        {
            shipments = [];
        }
    }

    private static string GetBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

