        <p class="lead text-muted">Enter your tracking number to check shipment status and estimated delivery.</p>
    </div>

    <div class="row justify-content-center">
        <div class="col-md-8 col-lg-6">
            <div class="input-group input-group-lg mb-3">
                <input type="text" class="form-control" placeholder="e.g. SHP-20260501-100001"
                       @bind="trackingNumber" @bind:event="oninput"
                       @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                    @if (isLoading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Track
                </button>
            </div>

            @if (searched && shipment is null)
            {
                <div class="alert alert-warning">
                    <strong>Not found.</strong> No shipment matches tracking number "<strong>@searchedNumber</strong>".
                </div>
            }

            @if (shipment is not null)
            {
                <div class="card shadow-sm">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@shipment.TrackingNumber</strong>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                    </div>
                    <div class="card-body">
                        <p><strong>Description:</strong> @shipment.Description</p>
                        <p><strong>Origin:</strong> @shipment.Origin</p>
                        <p><strong>Destination:</strong> @shipment.Destination</p>
                        <p><strong>Shipped:</strong> @shipment.CreatedAt.ToString("MMM dd, yyyy")</p>
                        @if (shipment.EstimatedDelivery.HasValue)
                        {
                            <p>
                                <strong>Estimated Delivery:</strong>
                                @shipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")
                                @if (shipment.Status != ShipmentTracker.Client.Models.ShipmentStatus.Delivered)
                                {
                                    var daysLeft = (shipment.EstimatedDelivery.Value - DateTime.UtcNow).Days;
                                    <span class="text-muted">
                                        (@(daysLeft > 0 ? $"in {daysLeft} day(s)" : "arriving soon"))
                                    </span>
                                }
                            </p>
                        }
                    </div>
                </div>
            }
        </div>
    </div>
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool searched;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isLoading = true;
        searched = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
        isLoading = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

